<script>
  import { onDestroy, onMount } from 'svelte'
  import { PDFDocument, StandardFonts, rgb } from 'pdf-lib'

  const localeByLang = { es: 'es-ES', en: 'en-US', fr: 'fr-FR', ca: 'ca-ES', pt: 'pt-PT', eu: 'eu-ES' }
  const languages = [['es', 'ES'], ['en', 'EN'], ['fr', 'FR'], ['ca', 'CA'], ['pt', 'PT'], ['eu', 'EU']]
  const countries = [['ES', 'España'], ['PT', 'Portugal'], ['FR', 'Francia'], ['US', 'Estados Unidos'], ['GB', 'Reino Unido'], ['DE', 'Alemania'], ['IT', 'Italia']]
  const regions = {
    ES: [['', 'Todo el país'], ['ES-AN', 'Andalucía'], ['ES-CT', 'Cataluña'], ['ES-EX', 'Extremadura'], ['ES-GA', 'Galicia'], ['ES-MD', 'Madrid'], ['ES-PV', 'País Vasco'], ['ES-VC', 'Comunidad Valenciana']],
    US: [['', 'Whole country'], ['US-CA', 'California'], ['US-FL', 'Florida'], ['US-NY', 'New York'], ['US-TX', 'Texas']]
  }

  const dict = {
    es: {
      skip: 'Saltar al contenido', navHome: 'Inicio', navWizard: 'Asistente', navPreview: 'Vista previa', navPdf: 'Generar PDF', theme: 'Tema', themeLabel: 'Cambiar modo claro u oscuro', menu: 'Abrir menú de navegación', badge: 'Asistente de calendario imprimible', title: 'Crea tu calendario paso a paso', subtitle: 'Te iré preguntando la configuración, explicando cada decisión y al final tendrás un resumen editable, vista previa y PDF descargable.', step: 'Paso', of: 'de', back: 'Atrás', next: 'Siguiente', generating: 'Generando...', generatePdf: 'Generar PDF', selectedOptions: 'Opciones seleccionadas', preview: 'Vista previa', readyTitle: 'Tu calendario está listo', readyText: 'Puedes revisarlo aquí, descargarlo o volver a cambiar cualquier paso del asistente.', download: 'Descargar PDF', openPreview: 'Abrir vista previa', messageOk: 'PDF generado. Puedes verlo, descargarlo o cambiar opciones abajo.', messageError: 'No se pudo generar el PDF. Revisa la configuración e inténtalo de nuevo.', months: ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'], week: ['L','M','X','J','V','S','D'], steps: [ ['date','¿Desde cuándo empieza?','Elige el primer mes y el año. El calendario se generará a partir de esa fecha.'], ['range','¿Cuántos meses quieres?','Puedes crear desde un calendario de un solo mes hasta un planificador anual completo.'], ['page','¿Cómo se colocan en la página?','Elige tamaño, orientación, meses por página y columnas. Las columnas controlan cuántos meses aparecen en cada fila.'], ['content','¿Qué debe aparecer?','Activa festivos, fines de semana, números de semana, días externos o zona de notas según el uso que quieras darle.'], ['style','¿Qué aspecto prefieres?','Configura tamaño de los días, color, bordes redondeados y pie de página con la fuente.'], ['summary','Resumen y vista previa','Revisa las opciones, cambia lo que necesites y genera el PDF cuando esté todo listo.'] ], labels: { startMonth:'Mes inicial', startMonthHelp:'Será el primer mes del calendario.', startYear:'Año inicial', startYearHelp:'Útil para calendarios futuros, escolares o laborales.', custom:'Personalizado', paper:'Tamaño de papel', paperHelp:'A4 suele ser la mejor opción para imprimir en casa.', orientation:'Orientación', orientationHelp:'Horizontal da más espacio para varios meses.', landscape:'Horizontal', portrait:'Vertical', monthsPerPage:'Meses por página', monthsPerPageHelp:'Cuantos más meses, más compacto queda.', columns:'Columnas de meses', columnsHelp:'Define cuántos meses van en cada fila dentro de una página.', auto:'Auto', holidays:'Incluir festivos', holidaysHelp:'Consulta date.nager.at según país y región.', country:'País', region:'Región', weekends:'Sombrear fines de semana', weekendsHelp:'Facilita leer calendarios laborales.', weekNumbers:'Mostrar números de semana', weekNumbersHelp:'Útil para planificación profesional.', outsideDays:'Mostrar días de otros meses', outsideDaysHelp:'Rellena la cuadrícula completa.', notes:'Añadir zona de notas', notesHelp:'Deja espacio para apuntes.', daySize:'Tamaño de los días', daySizeHelp:'Grande es mejor para pared; pequeño para planificadores.', compact:'Pequeños', comfortable:'Medios', large:'Grandes', colorMode:'Color', colorModeHelp:'Blanco y negro ahorra tinta.', color:'A color', grayscale:'Blanco y negro', rounded:'Celdas redondeadas', footer:'Añadir fuente en el pie', change:'Cambiar' }, summary: { start:'Inicio', duration:'Duración', page:'Página', content:'Contenido', style:'Estilo', month:'mes', months:'meses', columns:'columnas', column:'columna' } },
    en: {
      skip: 'Skip to content', navHome: 'Home', navWizard: 'Wizard', navPreview: 'Preview', navPdf: 'Generate PDF', theme: 'Theme', themeLabel: 'Toggle light or dark mode', menu: 'Open navigation menu', badge: 'Printable calendar wizard', title: 'Create your calendar step by step', subtitle: 'I will ask for each setting, explain every option, and finish with an editable summary, preview and downloadable PDF.', step: 'Step', of: 'of', back: 'Back', next: 'Next', generating: 'Generating...', generatePdf: 'Generate PDF', selectedOptions: 'Selected options', preview: 'Preview', readyTitle: 'Your calendar is ready', readyText: 'Review it here, download it, or go back and change any step.', download: 'Download PDF', openPreview: 'Open preview', messageOk: 'PDF generated. You can preview it, download it, or change options below.', messageError: 'The PDF could not be generated. Check the settings and try again.', months: ['January','February','March','April','May','June','July','August','September','October','November','December'], week: ['M','T','W','T','F','S','S'], steps: [ ['date','When should it start?','Choose the first month and year. The calendar will be generated from that date.'], ['range','How many months do you need?','Create anything from a single-month calendar to a full yearly planner.'], ['page','How should months be placed?','Choose paper size, orientation, months per page and columns. Columns control how many months appear in each row.'], ['content','What should be included?','Enable holidays, weekends, week numbers, outside days or a notes area depending on your use case.'], ['style','Which style do you prefer?','Configure day size, color, rounded cells and source footer.'], ['summary','Summary and preview','Review the settings, change anything you need and generate the PDF when ready.'] ], labels: { startMonth:'Start month', startMonthHelp:'This will be the first calendar month.', startYear:'Start year', startYearHelp:'Useful for future, school or work calendars.', custom:'Custom', paper:'Paper size', paperHelp:'A4 is usually best for home printing.', orientation:'Orientation', orientationHelp:'Landscape gives more room for multiple months.', landscape:'Landscape', portrait:'Portrait', monthsPerPage:'Months per page', monthsPerPageHelp:'More months means a more compact layout.', columns:'Month columns', columnsHelp:'How many months should appear per row on each page.', auto:'Auto', holidays:'Include holidays', holidaysHelp:'Uses date.nager.at by country and region.', country:'Country', region:'Region', weekends:'Shade weekends', weekendsHelp:'Makes work calendars easier to read.', weekNumbers:'Show week numbers', weekNumbersHelp:'Useful for professional planning.', outsideDays:'Show days from other months', outsideDaysHelp:'Fills the whole grid.', notes:'Add notes area', notesHelp:'Leaves space for notes.', daySize:'Day size', daySizeHelp:'Large is better for wall calendars; small for planners.', compact:'Small', comfortable:'Medium', large:'Large', colorMode:'Color', colorModeHelp:'Black and white saves ink.', color:'Color', grayscale:'Black and white', rounded:'Rounded cells', footer:'Add source in footer', change:'Change' }, summary: { start:'Start', duration:'Duration', page:'Page', content:'Content', style:'Style', month:'month', months:'months', columns:'columns', column:'column' } },
    fr: {}, ca: {}, pt: {}, eu: {}
  }
  dict.fr = { ...dict.en, navHome:'Accueil', navWizard:'Assistant', navPreview:'Aperçu', navPdf:'Générer PDF', theme:'Thème', badge:'Assistant de calendrier imprimable', title:'Créez votre calendrier étape par étape', subtitle:'Je vous guide dans la configuration, puis vous obtenez un résumé modifiable, un aperçu et un PDF.', months:['janvier','février','mars','avril','mai','juin','juillet','août','septembre','octobre','novembre','décembre'] }
  dict.ca = { ...dict.es, badge:'Assistent de calendari imprimible', title:'Crea el calendari pas a pas', subtitle:'Et preguntaré la configuració, explicaré cada opció i al final tindràs resum editable, vista prèvia i PDF.', months:['gener','febrer','març','abril','maig','juny','juliol','agost','setembre','octubre','novembre','desembre'] }
  dict.pt = { ...dict.es, badge:'Assistente de calendário para imprimir', title:'Crie seu calendário passo a passo', subtitle:'Vou perguntar a configuração, explicar cada opção e no final mostrar resumo editável, prévia e PDF.', months:['janeiro','fevereiro','março','abril','maio','junho','julho','agosto','setembro','outubro','novembro','dezembro'] }
  dict.eu = { ...dict.es, badge:'Egutegi inprimagarriaren laguntzailea', title:'Sortu egutegia pausoz pauso', subtitle:'Ezarpenak galdetuko dizkizut eta amaieran laburpen editagarria, aurrebista eta PDFa izango dituzu.', months:['urtarrila','otsaila','martxoa','apirila','maiatza','ekaina','uztaila','abuztua','iraila','urria','azaroa','abendua'] }

  let language = 'es'
  let theme = 'light'
  let menuOpen = false
  let stepIndex = 0
  let startMonth = new Date().getMonth()
  let startYear = new Date().getFullYear()
  let totalMonths = 12
  let monthsPerPage = 2
  let monthColumns = 'auto'
  let pageSize = 'A4'
  let orientation = 'landscape'
  let showHolidays = true
  let country = 'ES'
  let region = 'ES-EX'
  let shadeWeekends = true
  let showWeekNumbers = false
  let showEmptyDays = false
  let showNotes = false
  let daySize = 'comfortable'
  let colorMode = 'color'
  let roundedCells = true
  let includeFooter = true
  let pdfUrl = ''
  let isGenerating = false
  let message = ''

  $: t = dict[language] || dict.es
  $: steps = t.steps.map(([key, title, help]) => ({ key, title, help }))
  $: currentStep = steps[stepIndex]
  $: monthNames = t.months
  $: weekNames = t.week
  $: availableRegions = regions[country] || [['', t.labels?.auto || 'All']]
  $: if (!availableRegions.some(([code]) => code === region)) region = ''
  $: calendarMonths = Array.from({ length: Number(totalMonths) }, (_, index) => addMonths(Number(startYear), Number(startMonth), index))
  $: computedColumns = getColumnCount(Number(monthsPerPage))
  $: selectedSummary = [
    [t.summary.start, `${monthNames[startMonth]} ${startYear}`],
    [t.summary.duration, `${totalMonths} ${Number(totalMonths) === 1 ? t.summary.month : t.summary.months}`],
    [t.summary.page, `${pageSize}, ${orientation === 'landscape' ? t.labels.landscape : t.labels.portrait}, ${monthsPerPage} / page, ${computedColumns} ${computedColumns === 1 ? t.summary.column : t.summary.columns}`],
    [t.summary.content, contentSummary()],
    [t.summary.style, `${daySizeLabel(daySize)}, ${colorMode === 'color' ? t.labels.color : t.labels.grayscale}`]
  ]

  onMount(() => {
    const storedTheme = localStorage.getItem('printacalendar-theme') || localStorage.getItem('alon-tools-theme') || localStorage.getItem('theme')
    theme = storedTheme || (window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light')
    document.documentElement.dataset.theme = theme
    const storedLang = localStorage.getItem('printacalendar-language')
    if (storedLang && languages.some(([code]) => code === storedLang)) language = storedLang
    const onKeydown = (event) => { if (event.key === 'Escape') menuOpen = false }
    const mq = window.matchMedia('(min-width: 981px)')
    const onMediaChange = (event) => { if (event.matches) menuOpen = false }
    document.addEventListener('keydown', onKeydown)
    mq.addEventListener('change', onMediaChange)
    return () => { document.removeEventListener('keydown', onKeydown); mq.removeEventListener('change', onMediaChange) }
  })
  onDestroy(() => revokePdf())

  function toggleTheme() { theme = theme === 'dark' ? 'light' : 'dark'; document.documentElement.dataset.theme = theme; localStorage.setItem('printacalendar-theme', theme); localStorage.setItem('alon-tools-theme', theme); localStorage.setItem('theme', theme) }
  function changeLanguage(code) { language = code; localStorage.setItem('printacalendar-language', code); document.documentElement.lang = code; menuOpen = false }
  function nextStep() { stepIndex = Math.min(stepIndex + 1, steps.length - 1) }
  function previousStep() { stepIndex = Math.max(stepIndex - 1, 0) }
  function goToStep(index) { stepIndex = index; menuOpen = false }
  function addMonths(year, month, amount) { const date = new Date(year, month + amount, 1); return { year: date.getFullYear(), month: date.getMonth() } }
  function getColumnCount(perPage) { if (monthColumns !== 'auto') return Math.min(Number(monthColumns), perPage); if (perPage === 1) return 1; if (perPage === 2) return orientation === 'landscape' ? 2 : 1; if (perPage === 3) return orientation === 'landscape' ? 3 : 1; if (perPage === 4) return 2; return orientation === 'landscape' ? 3 : 2 }
  function daysForMonth(year, month) { const first = new Date(year, month, 1); const offset = (first.getDay() + 6) % 7; const days = new Date(year, month + 1, 0).getDate(); const previousDays = new Date(year, month, 0).getDate(); const cells = []; for (let i = 0; i < offset; i += 1) cells.push({ day: previousDays - offset + i + 1, muted: true, weekend: i >= 5 }); for (let day = 1; day <= days; day += 1) { const weekday = (new Date(year, month, day).getDay() + 6) % 7; cells.push({ day, muted: false, weekend: weekday >= 5 }) } while (cells.length % 7 !== 0 || cells.length < 35) { const day = cells.length - offset - days + 1; const weekday = (new Date(year, month + 1, day).getDay() + 6) % 7; cells.push({ day, muted: true, weekend: weekday >= 5 }) } return showEmptyDays ? cells : cells.map((cell) => cell.muted ? { ...cell, day: '' } : cell) }
  function daySizeLabel(value) { return value === 'large' ? t.labels.large : value === 'compact' ? t.labels.compact : t.labels.comfortable }
  function contentSummary() { const items = []; if (showHolidays) items.push(`${t.labels.holidays}: ${country}${region ? ` / ${region}` : ''}`); if (shadeWeekends) items.push(t.labels.weekends); if (showWeekNumbers) items.push(t.labels.weekNumbers); if (showNotes) items.push(t.labels.notes); return items.length ? items.join(', ') : '-' }
  function pageDimensions() { const sizes = { A4: [595.28, 841.89], A3: [841.89, 1190.55], Letter: [612, 792] }; let [width, height] = sizes[pageSize] || sizes.A4; if (orientation === 'landscape') [width, height] = width > height ? [width, height] : [height, width]; if (orientation === 'portrait') [width, height] = width < height ? [width, height] : [height, width]; return [width, height] }

  async function generatePdf() {
    isGenerating = true; message = ''; revokePdf()
    try {
      const pdf = await PDFDocument.create(); const font = await pdf.embedFont(StandardFonts.Helvetica); const bold = await pdf.embedFont(StandardFonts.HelveticaBold); const [width, height] = pageDimensions(); const perPage = Number(monthsPerPage); const primary = colorMode === 'color' ? rgb(0.94, 0.32, 0.24) : rgb(0.1, 0.1, 0.1); const soft = colorMode === 'color' ? rgb(1, 0.95, 0.93) : rgb(0.94, 0.94, 0.94); const weekend = colorMode === 'color' ? rgb(1, 0.92, 0.86) : rgb(0.9, 0.9, 0.9)
      for (let i = 0; i < calendarMonths.length; i += perPage) { const page = pdf.addPage([width, height]); const slice = calendarMonths.slice(i, i + perPage); const cols = getColumnCount(perPage); const rows = Math.ceil(slice.length / cols); const gap = 18; const margin = 36; const footerSpace = includeFooter ? 22 : 0; const blockWidth = (width - margin * 2 - gap * (cols - 1)) / cols; const blockHeight = (height - margin * 2 - footerSpace - gap * (rows - 1)) / rows; slice.forEach((item, index) => { const col = index % cols; const row = Math.floor(index / cols); const x = margin + col * (blockWidth + gap); const y = height - margin - (row + 1) * blockHeight - row * gap; drawMonth(page, { ...item, x, y, w: blockWidth, h: blockHeight, font, bold, primary, soft, weekend }) }); if (includeFooter) page.drawText('printacalendar.alon.one', { x: margin, y: 18, size: 9, font, color: rgb(0.4, 0.45, 0.52) }) }
      const bytes = await pdf.save(); pdfUrl = URL.createObjectURL(new Blob([bytes], { type: 'application/pdf' })); message = t.messageOk; stepIndex = steps.length - 1
    } catch (error) { message = t.messageError; console.error(error) } finally { isGenerating = false }
  }
  function drawMonth(page, data) { const { year, month, x, y, w, h, font, bold, primary, soft, weekend } = data; const title = `${monthNames[month]} ${year}`; const titleSize = daySize === 'large' ? 18 : 15; page.drawRectangle({ x, y, width: w, height: h, color: rgb(1, 1, 1), borderColor: rgb(0.86, 0.88, 0.92), borderWidth: 1 }); page.drawRectangle({ x, y: y + h - 34, width: w, height: 34, color: soft }); page.drawText(title.charAt(0).toUpperCase() + title.slice(1), { x: x + 12, y: y + h - 23, size: titleSize, font: bold, color: primary }); const top = y + h - 56; const cellW = w / 7; const notesSpace = showNotes ? 34 : 0; const cellH = Math.max(16, (h - 72 - notesSpace) / 7); weekNames.forEach((name, index) => page.drawText(name, { x: x + index * cellW + 8, y: top, size: 9, font: bold, color: rgb(0.35, 0.39, 0.46) })); daysForMonth(year, month).slice(0, 42).forEach((cell, index) => { const col = index % 7; const row = Math.floor(index / 7); const cx = x + col * cellW; const cy = top - 12 - (row + 1) * cellH; if (shadeWeekends && cell.weekend && !cell.muted) page.drawRectangle({ x: cx + 2, y: cy + 2, width: cellW - 4, height: cellH - 4, color: weekend }); page.drawRectangle({ x: cx, y: cy, width: cellW, height: cellH, borderColor: rgb(0.88, 0.9, 0.93), borderWidth: 0.5 }); if (cell.day) page.drawText(String(cell.day), { x: cx + 6, y: cy + cellH - 14, size: daySize === 'large' ? 12 : daySize === 'compact' ? 8 : 10, font, color: cell.muted ? rgb(0.65, 0.68, 0.72) : rgb(0.08, 0.1, 0.14) }) }); if (showNotes) { page.drawText('Notes', { x: x + 10, y: y + 20, size: 9, font: bold, color: rgb(0.4, 0.45, 0.52) }); page.drawLine({ start: { x: x + 48, y: y + 22 }, end: { x: x + w - 10, y: y + 22 }, thickness: 0.5, color: rgb(0.82, 0.85, 0.9) }) } }
  function revokePdf() { if (pdfUrl) URL.revokeObjectURL(pdfUrl); pdfUrl = '' }
</script>

<svelte:head><title>{t.title} | Print a Calendar</title><meta name="description" content={t.subtitle} /></svelte:head>

<a href="#main" class="skip-link">{t.skip}</a>
<header class:is-menu-open={menuOpen} class="site-header"><div class="page-shell header-inner"><a href="/" class="brand" aria-label="Print a Calendar"><span class="brand-mark">PC</span><strong>Print a Calendar</strong></a><button class="menu-toggle" type="button" aria-label={t.menu} aria-controls="site-menu" aria-expanded={menuOpen} on:click={() => menuOpen = !menuOpen}><span></span><span></span><span></span></button><div class="header-right" id="site-menu"><nav aria-label="Main"><a href="#main" on:click={() => menuOpen = false}>{t.navHome}</a><a href="#wizard" on:click={() => { goToStep(0); menuOpen = false }}>{t.navWizard}</a><a href="#preview" on:click={() => { goToStep(5); menuOpen = false }}>{t.navPreview}</a><button class="nav-button" type="button" on:click={() => { generatePdf(); menuOpen = false }}>{t.navPdf}</button></nav><div class="header-actions"><button class="theme-toggle" type="button" aria-label={t.themeLabel} aria-pressed={theme === 'dark'} on:click={toggleTheme}><span>{theme === 'dark' ? '🌙' : '☀️'}</span><span class="theme-toggle-text">{t.theme}</span></button><div class="language-switcher" aria-label="Language">{#each languages as item}<button type="button" class:active={language === item[0]} on:click={() => changeLanguage(item[0])}>{item[1]}</button>{/each}</div></div></div></div></header>

<main id="main" class="wizard-shell"><section class="hero"><span class="badge">{t.badge}</span><h1>{t.title}</h1><p>{t.subtitle}</p></section><section id="wizard" class="wizard-layout"><aside class="steps-panel">{#each steps as step, index}<button class:active={index === stepIndex} class:done={index < stepIndex} on:click={() => goToStep(index)}><span>{index + 1}</span><strong>{step.title}</strong></button>{/each}</aside><section class="wizard-card"><p class="step-kicker">{t.step} {stepIndex + 1} {t.of} {steps.length}</p><h2>{currentStep.title}</h2><p class="help">{currentStep.help}</p>
{#if currentStep.key === 'date'}<div class="field-grid two"><label>{t.labels.startMonth}<select bind:value={startMonth}>{#each monthNames as name, index}<option value={index}>{name}</option>{/each}</select><small>{t.labels.startMonthHelp}</small></label><label>{t.labels.startYear}<input type="number" min="1900" max="2100" bind:value={startYear} /><small>{t.labels.startYearHelp}</small></label></div>{:else if currentStep.key === 'range'}<div class="choice-grid">{#each [1,3,6,12,18,24] as amount}<button class:selected={Number(totalMonths) === amount} on:click={() => totalMonths = amount}>{amount} {amount === 1 ? t.summary.month : t.summary.months}</button>{/each}</div><label class="range-field">{t.labels.custom}<input type="range" min="1" max="24" bind:value={totalMonths} /><strong>{totalMonths}</strong></label>{:else if currentStep.key === 'page'}<div class="field-grid four"><label>{t.labels.paper}<select bind:value={pageSize}><option>A4</option><option>A3</option><option>Letter</option></select><small>{t.labels.paperHelp}</small></label><label>{t.labels.orientation}<select bind:value={orientation}><option value="landscape">{t.labels.landscape}</option><option value="portrait">{t.labels.portrait}</option></select><small>{t.labels.orientationHelp}</small></label><label>{t.labels.monthsPerPage}<select bind:value={monthsPerPage}>{#each [1,2,3,4,6,8,9,12] as n}<option value={n}>{n}</option>{/each}</select><small>{t.labels.monthsPerPageHelp}</small></label><label>{t.labels.columns}<select bind:value={monthColumns}><option value="auto">{t.labels.auto}</option>{#each [1,2,3,4] as n}<option value={n}>{n}</option>{/each}</select><small>{t.labels.columnsHelp}</small></label></div>{:else if currentStep.key === 'content'}<div class="toggle-grid"><label><input type="checkbox" bind:checked={showHolidays} /> {t.labels.holidays}<small>{t.labels.holidaysHelp}</small></label>{#if showHolidays}<label>{t.labels.country}<select bind:value={country}>{#each countries as item}<option value={item[0]}>{item[1]}</option>{/each}</select></label><label>{t.labels.region}<select bind:value={region}>{#each availableRegions as item}<option value={item[0]}>{item[1]}</option>{/each}</select></label>{/if}<label><input type="checkbox" bind:checked={shadeWeekends} /> {t.labels.weekends}<small>{t.labels.weekendsHelp}</small></label><label><input type="checkbox" bind:checked={showWeekNumbers} /> {t.labels.weekNumbers}<small>{t.labels.weekNumbersHelp}</small></label><label><input type="checkbox" bind:checked={showEmptyDays} /> {t.labels.outsideDays}<small>{t.labels.outsideDaysHelp}</small></label><label><input type="checkbox" bind:checked={showNotes} /> {t.labels.notes}<small>{t.labels.notesHelp}</small></label></div>{:else if currentStep.key === 'style'}<div class="field-grid two"><label>{t.labels.daySize}<select bind:value={daySize}><option value="compact">{t.labels.compact}</option><option value="comfortable">{t.labels.comfortable}</option><option value="large">{t.labels.large}</option></select><small>{t.labels.daySizeHelp}</small></label><label>{t.labels.colorMode}<select bind:value={colorMode}><option value="color">{t.labels.color}</option><option value="grayscale">{t.labels.grayscale}</option></select><small>{t.labels.colorModeHelp}</small></label><label class="check"><input type="checkbox" bind:checked={roundedCells} /> {t.labels.rounded}</label><label class="check"><input type="checkbox" bind:checked={includeFooter} /> {t.labels.footer}</label></div>{:else}<div id="preview" class="summary-grid"><div><h3>{t.selectedOptions}</h3><dl>{#each selectedSummary as row}<div><dt>{row[0]}</dt><dd>{row[1]}</dd></div>{/each}</dl><div class="edit-actions">{#each steps.slice(0, 5) as step, index}<button on:click={() => goToStep(index)}>{t.labels.change} {index + 1}</button>{/each}</div></div><div><h3>{t.preview}</h3><div class="calendar-preview"><h4>{monthNames[calendarMonths[0].month]} {calendarMonths[0].year}</h4><div class="week-row">{#each weekNames as day}<strong>{day}</strong>{/each}</div><div class="days-row">{#each daysForMonth(calendarMonths[0].year, calendarMonths[0].month).slice(0, 42) as cell}<span class:muted={cell.muted} class:weekend={shadeWeekends && cell.weekend && !cell.muted}>{cell.day}</span>{/each}</div></div></div></div>{/if}
{#if message}<p class="message">{message}</p>{/if}<div class="wizard-actions"><button class="secondary" on:click={previousStep} disabled={stepIndex === 0}>{t.back}</button>{#if stepIndex < steps.length - 1}<button class="primary" on:click={nextStep}>{t.next}</button>{:else}<button class="primary" on:click={generatePdf} disabled={isGenerating}>{isGenerating ? t.generating : t.generatePdf}</button>{/if}</div></section></section>{#if pdfUrl}<section class="result-panel"><div><h2>{t.readyTitle}</h2><p>{t.readyText}</p></div><div class="result-actions"><a class="primary link" href={pdfUrl} download="calendario-printacalendar.pdf">{t.download}</a><button class="secondary" on:click={() => window.open(pdfUrl, '_blank')}>{t.openPreview}</button></div><iframe title={t.preview} src={pdfUrl}></iframe></section>{/if}</main>

